/**
 * Login.jsx
 * ─────────────────────────────────────────────────────────────
 * Página de autenticación (login + registro en una sola vista).
 * Diseño minimalista bancario con animación de entrada.
 */

import { useState }                    from 'react'
import { useNavigate }                 from 'react-router-dom'
import { loginUser, registerUser }     from '../api/authApi'
import { useAuth }                     from '../context/AuthContext'
import Button                          from '../components/common/Button'
import ThemeToggle                     from '../components/common/ThemeToggle'
import styles                          from './Login.module.css'

const INITIAL_FORM = { name: '', email: '', password: '' }

export default function Login() {
  const [mode,    setMode]    = useState('login')
  const [form,    setForm]    = useState(INITIAL_FORM)
  const [error,   setError]   = useState(null)
  const [loading, setLoading] = useState(false)
  const { login }  = useAuth()
  const navigate   = useNavigate()

  const handleChange = (e) => {
    setForm((f) => ({ ...f, [e.target.name]: e.target.value }))
    setError(null)
  }

  const handleSubmit = async (e) => {
    e.preventDefault()
    setLoading(true)
    setError(null)

    try {
      const fn  = mode === 'login' ? loginUser : registerUser
      const res = await fn(form)
      login(res.user, res.token)
      navigate('/')
    } catch (err) {
      setError(err.response?.data?.error || 'Error al procesar la solicitud.')
    } finally {
      setLoading(false)
    }
  }

  const switchMode = () => {
    setMode((m) => (m === 'login' ? 'register' : 'login'))
    setForm(INITIAL_FORM)
    setError(null)
  }

  return (
    <div className={styles.page}>
      {/* Toggle de tema en esquina superior derecha */}
      <div className={styles.themeBtn}>
        <ThemeToggle />
      </div>

      <div className={`${styles.container} animate-fade-up`}>
        {/* Marca */}
        <div className={styles.brand}>
          <span className={styles.brandIcon}>◈</span>
          <h1 className={styles.brandName}>Finanzas</h1>
        </div>

        {/* Título de la vista */}
        <div className={styles.heading}>
          <h2>{mode === 'login' ? 'Bienvenido de nuevo' : 'Crea tu cuenta'}</h2>
          <p>{mode === 'login'
            ? 'Ingresa tus credenciales para continuar'
            : 'Empieza a gestionar tus finanzas hoy'}
          </p>
        </div>

        {/* Formulario */}
        <form onSubmit={handleSubmit} className={styles.form} noValidate>
          {mode === 'register' && (
            <div className="form-group animate-fade-up delay-1">
              <label className="field-label" htmlFor="name">Nombre completo</label>
              <input
                id="name" name="name" type="text"
                placeholder="Tu nombre"
                value={form.name}
                onChange={handleChange}
                required
                autoComplete="name"
              />
            </div>
          )}

          <div className="form-group animate-fade-up delay-2">
            <label className="field-label" htmlFor="email">Correo electrónico</label>
            <input
              id="email" name="email" type="email"
              placeholder="tu@correo.com"
              value={form.email}
              onChange={handleChange}
              required
              autoComplete="email"
            />
          </div>

          <div className="form-group animate-fade-up delay-3">
            <label className="field-label" htmlFor="password">Contraseña</label>
            <input
              id="password" name="password" type="password"
              placeholder="Mínimo 6 caracteres"
              value={form.password}
              onChange={handleChange}
              required
              minLength={6}
              autoComplete={mode === 'login' ? 'current-password' : 'new-password'}
            />
          </div>

          {error && (
            <div className="feedback feedback-error animate-fade-up">
              {error}
            </div>
          )}

          <Button
            type="submit"
            fullWidth
            size="lg"
            loading={loading}
            className="animate-fade-up delay-4"
          >
            {mode === 'login' ? 'Iniciar sesión' : 'Crear cuenta'}
          </Button>
        </form>

        {/* Cambio de modo */}
        <p className={styles.switchText}>
          {mode === 'login' ? '¿No tienes cuenta?' : '¿Ya tienes cuenta?'}{' '}
          <button type="button" className={styles.switchBtn} onClick={switchMode}>
            {mode === 'login' ? 'Regístrate gratis' : 'Inicia sesión'}
          </button>
        </p>
      </div>
    </div>
  )
}
